e\",\"video\"]}'),\n('Moltbot Local Task Orchestrator', 'Personal desktop agent handling calendar, code, and workflows locally.', 'agentic_ai', '{\"deployment\": \"local\", \"kit\": \"hq_starter\"}'),\n('Foundry Agent Factory', 'Model garden platform for rapid agent prototyping and deployment.', 'agentic_ai', '{\"platform\": \"Microsoft AI Foundry\", \"feature\": \"agent_factory\"}'),\n('Interactive Pattern Adaptation', 'Real-time evolution of behaviors via human-AI interaction loops.', 'self_improvement', '{\"method\": \"adaptive_interaction\", \"beyond\": \"memorization\"}'),\n('Modular Worker Checkpoints', 'Composable AI workers with state checkpointing for resilient execution.', 'agentic_ai', '{\"patterns\": \"Clawdbot HQ\", \"reliability\": \"checkpoint\"}'),\n('Crypto Scam Pattern Recognition', 'Detection of rugs, drainers, obfuscation via AI language and signature analysis.', 'security', '{\"domain\": \"crypto_scams\", \"patterns\": [\"fake_sig\",\"rugs\",\"drainers\"]}'),\n('MCP Agent Interoperability', 'Open frameworks enabling seamless tool and data sharing across agents.', 'agentic_ai', '{\"standard\": \"MCP\", \"benefit\": \"interchangeable\"}');\n